 98→// buildExportURL serializes a SearchRequest into query params matching the
 99→// export handler's parsing logic.
100→func buildExportURL(req search.SearchRequest) string {
101→	params := url.Values{}
102→
103→	if len(req.Filters) > 0 {
104→		data, _ := json.Marshal(req.Filters)
105→		params.Set("filters", string(data))
106→	}
107→
108→	if req.Sort != nil {
109→		params.Set("sort", req.Sort.Field)
110→		if req.Sort.Direction == search.SortDirectionDesc {
111→			params.Set("sortDir", "DESC")
112→		}
113→	}
114→
115→	if req.UserLocation != nil {
116→		params.Set("userLat", fmt.Sprintf("%g", req.UserLocation.Latitude))
117→		params.Set("userLng", fmt.Sprintf("%g", req.UserLocation.Longitude))
118→		if req.UserLocation.State != "" {
119→			params.Set("userState", req.UserLocation.State)
120→		}
121→	}
122→
123→	return "/api/export/csv?" + params.Encode()
124→}
