 14→)
 15→
 16→// TestContractMatrix_MCP runs the shared contract cases through the MCP
 17→// search handler, verifying that the MCP adapter produces the same
 18→// validation outcomes as the baseline.
 19→func TestContractMatrix_MCP(t *testing.T) {
 20→	t.Parallel()
 21→	defaultReg := search.NewRegistry()
 22→
 23→	for _, cc := range search.ContractCases() {
 24→		if cc.SkipMCP {
 25→			continue
 26→		}
 27→
 28→		t.Run(cc.Name, func(t *testing.T) {
 29→			t.Parallel()
 30→
 31→			reg := defaultReg
 32→			if cc.Registry != nil {
 33→				reg = cc.Registry
 34→			}
 35→
 36→			handler := makeSearchHandler(nil, reg)
 37→
 38→			in := searchInput{
 39→				Filters: cc.Request.Filters,
 40→				Limit:   cc.Request.Limit,
 41→				Offset:  cc.Request.Offset,
 42→			}
 43→
 44→			ctx := context.Background()
 45→			if cc.Authenticated {
 46→				ctx = auth.SetClaims(ctx, &auth.Claims{})
 47→			}
 48→
 49→			if cc.WantValid {
 50→				// Validation passes → handler proceeds to DB call → nil Querier panics.
 51→				// Run in a goroutine to isolate the panic from testing.T's recovery.
 52→				panicked := make(chan bool, 1)
 53→				errCh := make(chan error, 1)
 54→				go func() {
 55→					defer func() {
 56→						if r := recover(); r != nil {
 57→							panicked <- true
 58→						} else {
 59→							panicked <- false
 60→						}
 61→					}()
 62→					result, _, err := handler(ctx, nil, in)
 63→					if err != nil {
 64→						errCh <- err
 65→						return
 66→					}
 67→					if result.IsError {
 68→						errCh <- fmt.Errorf("expected valid request, got IsError with: %v", result.Content)
 69→						return
 70→					}
 71→					errCh <- nil
 72→				}()
 73→
 74→				select {
 75→				case p := <-panicked:
 76→					if !p {
 77→						t.Fatal("expected panic from nil DB (validation should have passed)")
 78→					}
 79→					// Panic from nil Querier = validation passed ✓
 80→				case err := <-errCh:
 81→					if err != nil {
 82→						t.Fatal(err)
 83→					}
 84→					// No panic and no error means it somehow succeeded (shouldn't happen with nil DB)
 85→				}
 86→				return
 87→			}
 88→
 89→			// Expect validation failure → IsError=true.
 90→			result, _, err := handler(ctx, nil, in)
 91→			if err != nil {
 92→				t.Fatalf("unexpected Go error: %v", err)
 93→			}
 94→			if !result.IsError {
 95→				t.Fatal("expected IsError=true for invalid request")
 96→			}
 97→
 98→			text, ok := result.Content[0].(*mcp.TextContent)
 99→			if !ok {
100→				t.Fatalf("expected TextContent, got %T", result.Content[0])
101→			}
102→
103→			var body struct {
104→				Errors []struct {
105→					Field   string `json:"field"`
106→					Message string `json:"message"`
107→				} `json:"errors"`
108→			}
109→			if err := json.Unmarshal([]byte(text.Text), &body); err != nil {
110→				t.Fatalf("decode error response: %v", err)
111→			}
112→			if len(body.Errors) == 0 {
113→				t.Fatal("expected validation errors in response")
114→			}
115→
116→			found := false
117→			for _, e := range body.Errors {
118→				if e.Field == cc.WantField && strings.Contains(e.Message, cc.WantContains) {
119→					found = true
120→					break
121→				}
122→			}
123→			if !found {
124→				t.Errorf("expected error field=%q containing %q, got: %+v",
125→					cc.WantField, cc.WantContains, body.Errors)
126→			}
127→		})
128→	}
129→}
